// Java 25 exam prep - Sequenced collections
// Learn: read both ends and reverse with the sequenced collections API.
SequencedCollection<String> q = new ArrayList<>(List.of("a", "b", "c"));
q.addFirst("start");
// getFirst and getLast read opposite ends.
String first = q.getFirst();
String last = q.getLast();
System.out.println(first + "/" + last + " " + q.reversed());
